import React from 'react';
import { motion } from 'framer-motion';
import { Lock, Flag } from '@phosphor-icons/react';

const miniAwards = [
  { emoji: '🥄', key: 'wooden_spoon', title: 'Wooden Spoon', tone: 'amber', format: (d) => d ? `${d.player} · ${d.points} pts` : '—' },
  { emoji: '🧊', key: 'freeze',       title: 'Freeze',       tone: 'sky',    format: (d) => d && d.drop > 0 ? `${d.player} · dropped ${d.drop} pts` : '—' },
  { emoji: '🔥', key: 'heater',       title: 'Heater',       tone: 'orange', format: (d) => d && d.gain > 0 ? `${d.player} · +${d.gain} pts` : '—' },
  { emoji: '🐢', key: 'slow_starter', title: 'Slow Starter', tone: 'emerald',format: (d) => d ? `${d.player} · ${d.points} pts on first 3` : '—' },
  { emoji: '🎯', key: 'clutch_king',  title: 'Clutch King',  tone: 'yellow', format: (d) => d ? `${d.player} · ${d.points} pts on last 3` : '—' },
];

const toneBg = {
  amber: 'bg-amber-500/10 border-amber-500/25',
  sky: 'bg-sky-500/10 border-sky-500/25',
  orange: 'bg-orange-500/10 border-orange-500/25',
  emerald: 'bg-emerald-500/10 border-emerald-500/25',
  yellow: 'bg-yellow-500/10 border-yellow-500/25',
  rose: 'bg-rose-500/10 border-rose-500/25',
  purple: 'bg-purple-500/10 border-purple-500/25',
  gold: 'bg-[#D4AF37]/10 border-[#D4AF37]/30',
};

const toneText = {
  amber: 'text-amber-300',
  sky: 'text-sky-300',
  orange: 'text-orange-300',
  emerald: 'text-emerald-300',
  yellow: 'text-yellow-300',
  rose: 'text-rose-300',
  purple: 'text-purple-300',
  gold: 'text-[#D4AF37]',
};

function AwardTile({ emoji, title, tone, winner, detail }) {
  return (
    <div className={`rounded-lg border ${toneBg[tone]} px-3 py-2.5`}>
      <div className="flex items-center gap-2 mb-1">
        <span className="text-lg leading-none">{emoji}</span>
        <span className={`text-[10px] uppercase tracking-wider font-semibold ${toneText[tone]}`}>{title}</span>
      </div>
      <p className="text-white text-sm font-semibold truncate">{winner}</p>
      {detail && <p className="text-[#A9C5B4] text-[11px] truncate">{detail}</p>}
    </div>
  );
}

function RoundCard({ round, index }) {
  if (!round.has_scores) {
    return (
      <motion.div
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: index * 0.05 }}
        className="rounded-xl border border-[#D4AF37]/15 bg-[#0F2C1D]/60 p-5 opacity-60"
      >
        <div className="flex items-center gap-3 mb-2">
          <Flag size={20} className="text-[#D4AF37]" weight="duotone" />
          <div>
            <h3 className="text-base font-serif text-[#D4AF37]">Round {round.round_number}</h3>
            <p className="text-xs text-[#A9C5B4]">{round.course}</p>
          </div>
        </div>
        <p className="text-xs text-[#A9C5B4]/60 italic mt-4">No scores logged for this round yet.</p>
      </motion.div>
    );
  }

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: index * 0.05 }}
      className="rounded-xl border border-[#D4AF37]/20 bg-[#0F2C1D]/90 p-5 shadow-xl"
    >
      <div className="flex items-start justify-between mb-4">
        <div className="flex items-center gap-3">
          <Flag size={22} className="text-[#D4AF37]" weight="duotone" />
          <div>
            <h3 className="text-lg font-serif text-[#D4AF37]">Round {round.round_number}</h3>
            <p className="text-xs text-[#A9C5B4] uppercase tracking-wider">{round.course}</p>
          </div>
        </div>
        <div className="flex gap-1 flex-wrap justify-end">
          {round.beer_hole && <span className="text-[10px] rounded-full px-2 py-0.5 bg-rose-500/15 text-rose-300 border border-rose-500/30">🍺 H{round.beer_hole}</span>}
          {round.joker_hole && <span className="text-[10px] rounded-full px-2 py-0.5 bg-purple-500/15 text-purple-300 border border-purple-500/30">🎭 H{round.joker_hole}</span>}
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
        {miniAwards.map(a => (
          <AwardTile
            key={a.key}
            emoji={a.emoji}
            title={a.title}
            tone={a.tone}
            winner={round[a.key]?.player || '—'}
            detail={a.format(round[a.key])}
          />
        ))}
        {round.beer_hole_winner && (
          <AwardTile
            emoji="🍺"
            title="Beer Hole"
            tone="rose"
            winner={round.beer_hole_winner.name}
            detail={`${round.beer_hole_winner.strokes} strokes on hole ${round.beer_hole} — buys drinks!`}
          />
        )}
        {round.joker_hole_winner && (
          <AwardTile
            emoji="🎭"
            title="Joker Hole"
            tone="purple"
            winner={round.joker_hole_winner.name}
            detail={`+${round.joker_hole_winner.bonus} bonus pts from hole ${round.joker_hole}`}
          />
        )}
      </div>
    </motion.div>
  );
}

export default function Awards({ awards }) {
  if (!awards?.season_complete) {
    const done = awards?.rounds_complete ?? 0;
    const total = awards?.total_rounds ?? 0;
    const pct = total > 0 ? Math.round((done / total) * 100) : 0;
    return (
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="max-w-xl mx-auto text-center py-16 px-6"
        data-testid="awards-locked"
      >
        <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-[#D4AF37]/10 border border-[#D4AF37]/30 mb-5">
          <Lock size={36} className="text-[#D4AF37]" weight="duotone" />
        </div>
        <h2 className="text-3xl sm:text-4xl font-serif text-[#D4AF37] mb-3">Season Awards Locked</h2>
        <p className="text-[#A9C5B4] text-sm mb-6 max-w-md mx-auto leading-relaxed">
          The banter is served cold at the end of the season. Once every player has logged every round, the trophies unlock.
        </p>
        <div className="rounded-xl border border-[#D4AF37]/20 bg-[#0F2C1D]/80 p-5 max-w-sm mx-auto">
          <div className="flex items-center justify-between mb-2 text-xs text-[#A9C5B4] uppercase tracking-wider">
            <span>Progress</span>
            <span className="font-bold text-[#D4AF37]">{done} / {total} rounds</span>
          </div>
          <div className="h-2 rounded-full bg-[#051A10] overflow-hidden">
            <motion.div
              initial={{ width: 0 }}
              animate={{ width: `${pct}%` }}
              transition={{ duration: 0.8, ease: 'easeOut' }}
              className="h-full bg-gradient-to-r from-[#D4AF37] to-[#F1D67E]"
            />
          </div>
          <p className="text-[11px] text-[#A9C5B4]/70 mt-3 italic">A round counts as complete once every active player has logged at least one score.</p>
        </div>
      </motion.div>
    );
  }

  const season = awards.season || {};

  return (
    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} data-testid="awards-section">
      {/* Header */}
      <div className="text-center mb-8">
        <p className="text-xs text-[#D4AF37] uppercase tracking-[0.2em] mb-1">🏆 Season Complete 🏆</p>
        <h2 className="text-3xl sm:text-4xl font-serif text-[#D4AF37] mb-2">Season Awards</h2>
        <p className="text-sm text-[#A9C5B4]">Banter, brags &amp; ridicule · {awards.total_rounds} rounds · {awards.active_players} players</p>
      </div>

      {/* Season-wide summary */}
      <div className="max-w-4xl mx-auto mb-10">
        <h3 className="text-xs text-[#A9C5B4] uppercase tracking-[0.15em] mb-3 flex items-center gap-2">Season Summary</h3>
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
          <div className={`rounded-xl border ${toneBg.amber} p-4`}>
            <div className="flex items-center gap-2 mb-2">
              <span className="text-2xl">🥄</span>
              <span className={`text-[11px] uppercase tracking-wider font-semibold ${toneText.amber}`}>Wooden Spoon Leader</span>
            </div>
            <p className="text-white font-bold text-base truncate">{season.wooden_spoon_leader?.player || '—'}</p>
            <p className="text-[#A9C5B4] text-xs">{season.wooden_spoon_leader?.count > 0 ? `${season.wooden_spoon_leader.count}× worst round` : 'Nobody stinkered yet'}</p>
            {season.longest_streak?.streak > 1 && (
              <p className={`text-[10px] mt-2 italic ${toneText.amber}`}>Longest streak: {season.longest_streak.player} ({season.longest_streak.streak}×)</p>
            )}
          </div>
          <div className={`rounded-xl border ${toneBg.purple} p-4`}>
            <div className="flex items-center gap-2 mb-2">
              <span className="text-2xl">🎭</span>
              <span className={`text-[11px] uppercase tracking-wider font-semibold ${toneText.purple}`}>Joker King (Season)</span>
            </div>
            <p className="text-white font-bold text-base truncate">{season.joker_king?.player || '—'}</p>
            <p className="text-[#A9C5B4] text-xs">
              {season.joker_king ? `+${season.joker_king.bonus} pts · ${season.joker_king.course} H${season.joker_king.hole}` : 'No joker hole set yet'}
            </p>
          </div>
          <div className={`rounded-xl border ${toneBg.gold} p-4`}>
            <div className="flex items-center gap-2 mb-2">
              <span className="text-2xl">🏆</span>
              <span className={`text-[11px] uppercase tracking-wider font-semibold ${toneText.gold}`}>Rounds Played</span>
            </div>
            <p className="text-white font-bold text-base">{awards.total_rounds} rounds</p>
            <p className="text-[#A9C5B4] text-xs">{awards.active_players} players · all complete</p>
          </div>
        </div>
      </div>

      {/* Per-round awards history */}
      <div className="max-w-4xl mx-auto">
        <h3 className="text-xs text-[#A9C5B4] uppercase tracking-[0.15em] mb-3">Per-Round Awards</h3>
        <div className="space-y-4">
          {awards.per_round.map((r, i) => <RoundCard key={r.round_number} round={r} index={i} />)}
        </div>
      </div>
    </motion.div>
  );
}
